  // For HyperLogLog with n_bits=0, we have 1 bucket
  // Test: AddElem(1), expect cardinality ≈ 1665180

  // If the hash of 1 gives position p, then:
  // cardinality = 0.79402 * 1 * 1 / (2^-p) = 0.79402 * 2^p
  // So: 1665180 = 0.79402 * 2^p
  // 2^p = 1665180 / 0.79402 ≈ 2097152
  // p = log2(2097152) ≈ 21

  double p = std::log2(1665180 / 0.79402);
  std::cout << "Expected position: " << p << std::endl;

  // For 262144 (which is 2^18), position of leading zeros + 1
  // 262144 in binary is 1000000000000000000 (1 followed by 18 zeros)
  // Leading zeros in 64-bit: 64 - 19 = 45
  // Position: 45 + 1 = 46

  uint64_t val = 262144;
  uint64_t leading_zeros = __builtin_clzll(val);
  std::cout << "262144 leading zeros: " << leading_zeros << ", position: " << (leading_zeros + 1) << std::endl;

  // For 1:
