#include <cmath>

#include "primer/hyperloglog.h"

namespace bustub {

/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  if (n_bits < 0) {
    // Handle invalid n_bits (negative is invalid)
    registers_ = std::vector<uint8_t>();
  } else if (n_bits == 0) {
    // n_bits=0 means 1 bucket
    registers_ = std::vector<uint8_t>(1, 0);
  } else {
    // Initialize registers with 0s
    uint64_t num_buckets = 1ULL << n_bits;
    registers_ = std::vector<uint8_t>(num_buckets, 0);
  }
}

/**
 * @brief Function that computes binary.
 *
 * @param[in] hash
 * @returns binary of a given hash
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  // Not used anymore - we compute position directly
  return std::bitset<BITSET_CAPACITY>(hash);
}

/**
 * @brief Function that computes leading zeros.
 *
 * @param[in] bset - binary values of a given bitset
 * @returns leading zeros of given binary set
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find the position of the leftmost 1 bit (rho function)
  // Count leading zeros from the most significant bit
  uint64_t val = bset.to_ullong();
  if (val == 0) {
    return BITSET_CAPACITY + 1;
  }
  // Position is leading zeros + 1
  // Use __builtin_clzll for 64-bit count leading zeros
  return __builtin_clzll(val) + 1;
}

/**
 * @brief Adds a value into the HyperLogLog.
 *
 * @param[in] val - value that's added into hyperloglog
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ < 0) {
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Hash the value
  hash_t hash_val = CalculateHash(val);

  // Extract bucket index from first n_bits
  uint64_t mask = (1ULL << n_bits_) - 1;
  uint64_t bucket_idx = hash_val & mask;

  // Extract the remaining bits
  hash_t remaining_bits = hash_val >> n_bits_;

  // Calculate position of leading zeros + 1 in remaining bits
  uint64_t leftmost_one_pos;
  if (remaining_bits == 0) {
    leftmost_one_pos = BITSET_CAPACITY + 1;
  } else {
    leftmost_one_pos = __builtin_clzll(remaining_bits) + 1;
  }

  // Update register with maximum position
  if (leftmost_one_pos > registers_[bucket_idx]) {
    registers_[bucket_idx] = static_cast<uint8_t>(leftmost_one_pos);
  }
}

/**
 * @brief Function that computes cardinality.
 */
template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  std::lock_guard<std::mutex> lock(mutex_);

  if (n_bits_ < 0 || registers_.empty()) {
    cardinality_ = 0;
    return;
  }

  // Calculate the number of buckets
  uint64_t m = registers_.size();

  // Calculate the sum of 2^-register_value
  double sum = 0.0;
  for (uint8_t reg_val : registers_) {
    sum += std::pow(2.0, -static_cast<double>(reg_val));
  }

  // Apply the HyperLogLog formula
  double raw_estimate = CONSTANT * m * m / sum;

  // Apply bias correction for small and large cardinalities
  // For simplicity, we'll use the basic formula and round to nearest integer
  cardinality_ = static_cast<size_t>(raw_estimate);
}

template class HyperLogLog<int64_t>;
template class HyperLogLog<std::string>;

}  // namespace bustub
