//===----------------------------------------------------------------------===//

#include <cmath>

#include "primer/hyperloglog_presto.h"

namespace bustub {

/** @brief Parameterized constructor. */
template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits) : cardinality_(0) {
  if (n_leading_bits < 0) {
    // Invalid n_leading_bits
    return;
  }

  // Initialize dense buckets and overflow buckets
  uint64_t num_buckets = 1ULL << n_leading_bits;
  dense_bucket_ = std::vector<std::bitset<DENSE_BUCKET_SIZE>>(num_buckets, 0);

  // Initialize overflow buckets with 0
  for (uint64_t i = 0; i < num_buckets; ++i) {
    overflow_bucket_[i] = 0;
  }
}

/** @brief Element is added for HLL calculation. */
template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (dense_bucket_.empty()) {
    return;
  }

  // Hash the value
  hash_t hash_val = CalculateHash(val);

  // Get number of leading bits
  uint64_t num_buckets = dense_bucket_.size();
  uint64_t num_bits = 0;
  uint64_t temp = num_buckets - 1;
  while (temp > 0) {
    num_bits++;
    temp >>= 1;
  }

  // Extract bucket index from first num_bits
  uint64_t mask = (1ULL << num_bits) - 1;
  uint64_t bucket_idx = hash_val & mask;

  // Extract the remaining bits
  hash_t remaining_bits = hash_val >> num_bits;

  // Find position of leftmost 1 bit
  uint64_t pos = 0;
  hash_t temp_bits = remaining_bits;
  while (temp_bits > 0) {
    pos++;
    temp_bits >>= 1;
  }
  if (remaining_bits == 0) {
    pos = 65;  // If no 1 bit found
  }

  // Update dense and overflow buckets
  uint64_t dense_val = pos & 0xF;  // Lower 4 bits
  uint64_t overflow_val = pos >> 4;  // Higher bits

  // Update dense bucket
  if (dense_val > dense_bucket_[bucket_idx].to_ullong()) {
    dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(dense_val);
    overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
  } else if (dense_val == dense_bucket_[bucket_idx].to_ullong() &&
             overflow_val > overflow_bucket_[bucket_idx].to_ullong()) {
    overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
  }
}

/** @brief Function to compute cardinality. */
template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (dense_bucket_.empty()) {
    cardinality_ = 0;
    return;
  }

  // Calculate the number of buckets
  uint64_t m = dense_bucket_.size();

  // Calculate the sum of 2^-position
  double sum = 0.0;
  for (size_t i = 0; i < dense_bucket_.size(); ++i) {
    uint64_t dense_val = dense_bucket_[i].to_ullong();
    uint64_t overflow_val = overflow_bucket_[i].to_ullong();

    // Reconstruct position from dense and overflow buckets
    uint64_t pos = (overflow_val << 4) | dense_val;

    sum += std::pow(2.0, -static_cast<double>(pos));
  }

  // Apply the HyperLogLog formula
  double raw_estimate = CONSTANT * m * m / sum;

  // Apply bias correction for small and large cardinalities
  cardinality_ = static_cast<uint64_t>(raw_estimate);
}

template class HyperLogLogPresto<int64_t>;
template class HyperLogLogPresto<std::string>;
}  // namespace bustub

